}

public static <T> T requireNonEmpty(final T obj, final String message) {
    // check for null first to give the most precise exception.
    Objects.requireNonNull(obj, message);
    if (isEmpty(obj)) {
        throw new IllegalArgumentException(message);
    }
    return obj;
}

